var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"에이미, 이쪽은 대강 정리가 끝난 것 같은데?","JPN":"エイミー、こっちはだいたい片付いたみたい。","ENG":"Amy, it looks like we're done here.","TWN":"艾米，看來我們的事情告一段落了。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 여기가 정말 스완이 있는 좌표가 확실한 거야?","JPN":"それより、本当にここがスワンのいる座標なの？","ENG":"But are you sure these coordinates are where Swan is hiding?","TWN":"但你確定這組座標是史旺藏身的地方嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"고심도라더니… 침식체도 그렇고, 풍경도 그렇고 그저 그런 이면세계들이랑 별로 다를 것도 없는데?","JPN":"高深度って言ってたけど……侵食体も、風景も別に他の裏世界と変わらない気がする。","ENG":"You said it was in the hyperdepths, but the Corruption rays and scenery don't look that different from the other Counterside worlds.","TWN":"所謂高深度……侵蝕體也好，風景也好，和那些普通的異界沒什麼差別嘛？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"스완은 대체 이런 곳에서 뭘 꾸미고 있는 거야?","JPN":"スワンってここでいったい何を企んでるのかな？","ENG":"What is Swan even planning in a place like this?","TWN":"史旺到底打算在這種地方做什麼？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뭐야, 너 설마 여기가 어디인지 몰라?","JPN":"なんだ。あんた、ここがどこなのか知らないわけ？","ENG":"Wait, you don't know where we are?","TWN":"等等，你不知道我們在哪裡？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"하도 자신만만하게 도와달라길래, 나는 당연히 목적지 정도는 짐작하고 있을 줄 알았는데?","JPN":"自信満々に力を貸してなんて言うから、当然目的地くらい見当ついてるのかと思ったよ。","ENG":"You asked for my help so confidently, so I assumed you at least had some idea of the destination.","TWN":"你那麼有把握地求我幫忙，我以為你至少知道目的地在哪。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무것도 모른다면서 다그칠 때는 언제고 이제 와서 딴소리야?","JPN":"さっきは「何も知らない」って怒ってたくせに。","ENG":"You kept pestering me about not knowing anything, and now you're the one playing dumb?","TWN":"你自己還不是一問三不知，還敢說我？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"내가 그런 걸 어떻게 알겠어? 애초에 네가 어디 간다고 알려주지도 않았잖아?","JPN":"私がそんなことを知ってるわけないじゃない。そもそもどこに行くのかも教えてもらってないし。","ENG":"How was I supposed to know? You never told me where we were going in the first place.","TWN":"我怎麼會知道？你一開始根本沒告訴我我們要去哪。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그래서 여기가 어디야?","JPN":"で、ここはどこなの？","ENG":"So, where are we?","TWN":"那我們到底在哪？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나는 스완이 숨어 있는 좌표라면, 조금 더 위험한 곳일 줄 알았는데?","JPN":"スワンが隠れてる座標って言うからには、もっと危険なところかと思ったよ。","ENG":"I thought the place where Swan is hiding would be more dangerous.","TWN":"我以為史旺藏身的地方會更危險。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"이왕 머리 굴린 김에 조금 더 머리를 굴려보는 게 어때?","JPN":"せっかくだからもっと頭使ってみたら？","ENG":"Since you're already thinking, why not think a bit harder?","TWN":"既然你已經在想了，不如多想一點？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"뻔하잖아. 애초에 다른 세계에서 도망쳐 온 엑자일러가 튀어봤자 어디로 튀겠어?","JPN":"決まってるでしょ？　他の世界から逃げてきたエグザイラーが隠れそうな場所って言えばさ。","ENG":"Isn't it obvious? If an Exile from another world was running away, where do you think they'd go?","TWN":"這不明顯嗎？如果一個來自其他世界的流浪者逃跑，他們會去哪？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"엑자일러……?","JPN":"エグザイラー……？","ENG":"An Exile...?","TWN":"流浪者……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 설마 여기가 스완의 고향 세계라는 거야?","JPN":"じゃあ、まさかここがスワンの故郷ってこと？","ENG":"Wait, you're saying this is Swan's home world?","TWN":"等等，你是說這是史旺的家鄉世界？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래, 육익의 동료 중에는 과거를 통찰하는 능력을 가진 녀석이 있거든.","JPN":"そう。六翼の仲間には過去を見通す能力を持ってるやつがいるんだよ。","ENG":"Yeah. One of my comrades at Six Wings has the power to perceive the past.","TWN":"沒錯。六翼的一位同伴有感知過去的能力。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 녀석이 알려준 스완의 고향 세계 좌표가 바로 여기야.","JPN":"そいつが教えてくれたスワンの故郷の座標がここってわけ。","ENG":"The coordinates she pinpointed are here, Swan's home world.","TWN":"她定位的座標就在這裡，史旺的家鄉世界。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐만 이곳이 이면세계라는 건, 스완의 세계가 이미 멸망해 버렸다는 뜻이잖아.","JPN":"待って。ここが裏世界だってことは、スワンの世界がもう滅亡してしまったってことじゃない。","ENG":"Hold on. If this place is part of the Counterside, doesn't that mean Swan's world was already destroyed?","TWN":"等等，如果這地方是異界的一部分，那不就代表史旺的世界早已被毀？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마, 그 멸망한 고향 세계에 다시 찾아왔다는 건……?","JPN":"まさか、その滅亡した故郷にまた来たってことは……？","ENG":"Wait, so her coming back to her ruined home world means...?","TWN":"那她回到她破碎的家鄉世界是想……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"큭큭, 이제야 눈치 챈 거야?","JPN":"ククッ、やっと気づいた？","ENG":"Keke. Finally starting to get it?","TWN":"呵呵，終於開始懂了？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"아마도 스완은 자신의 고향 세계를 되살릴 생각이겠지.","JPN":"たぶんスワンは自分の故郷を復活させるつもりなんだ。","ENG":"Swan is probably trying to restore it.","TWN":"史旺很可能想要恢復它。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그 <color=#ffd34c>세피라</color>라는 힘을 통해서 말이야.","JPN":"あの<color=#ffd34c>セフィラ</color>とかいう力でね。","ENG":"Using the power of <color=#ffd34c>Sephira</color>.","TWN":"利用<color=#ffd34c>生命樹</color>的力量。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"세피라라고……?","JPN":"セフィラ……？","ENG":"Sephira...?","TWN":"生命樹……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"틀림없어. 클리포트 게임이 진행되는 동안 나랑 스완은 관리 경계 구역에 있었으니까.","JPN":"間違いない。クリフォトゲームの途中に、あたしとスワンは管理警戒区域にいたから。","ENG":"I'm sure of it. During the Qliphoth Game, Swan and I were both in the perimeter zone.","TWN":"我很肯定。在克里福特遊戲期間，史旺和我都在警戒區。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"관리 경계 구역이라면…….","JPN":"管理警戒区域って……","ENG":"The perimeter zone...?","TWN":"警戒區……"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"AMY_SIX_NULL_NULL","text":{"KOREA":"그래, 내가 너를 기다리고 있던 그곳이지.","JPN":"そう、あたしがあんたを待ってたところさ。","ENG":"Yes. The place where I was waiting for you.","TWN":"是的，就是我等你的那個地方。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"AMY_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};